class Solution {
public:
    int numberOfArithmeticSlices(vector<int>& nums) {
        int n=nums.size(), ans=0;
        vector<unordered_map<long long,int>> dp(n);
        for(int i=0;i<n;i++)
            for(int j=0;j<i;j++){
                long long d=(long long)nums[i]-nums[j];
                int cnt=dp[j][d];
                if(cnt) ans+=cnt;
                dp[i][d]+=cnt+1;
            }
        return ans;
    }
};
